using System.Collections;
using TMPro;
using UnityEngine;

/// <summary>
/// Implementação concreta de INpcDialogueDisplay: balão de diálogo com TMP,
/// com efeito de escrita, paginação automática (overflow do TMP) e suporte
/// às tags do DialogueMarkupParser ([wait], [shake], [highlight], [page]).
///
/// Configuração esperada (montar no Editor, normalmente dentro de um Canvas):
/// - "panelRoot": GameObject raiz do balão (activado/desactivado em Show/Hide).
/// - "nameLabel": TMP_Text para o nome do falante. É desactivado automaticamente
///   quando a linha não tem nome (speakerName vazio).
/// - "bodyText": TMP_Text para o corpo da fala. O overflowMode é forçado para
///   "Page" no Awake — o TMP divide automaticamente o texto em páginas que
///   cabem na caixa, e cada página espera o botão de interação para avançar
///   (isto cobre o "balão enche" pedido). Quebras manuais com [page] funcionam
///   da mesma forma, mas terminam a página de imediato.
/// - "continueIndicator": GameObject opcional (ex: seta a piscar) mostrado
///   quando uma página está totalmente revelada e à espera do botão de
///   interação para continuar.
///
/// Depois de configurado, atribui este componente ao campo "Dialogue Display"
/// do(s) NpcController(s).
///
/// Nota sobre [highlight]: a falta de suporte nativo do TMP a contornos
/// animados por carácter, "destacado" é implementado como uma cor a pulsar
/// entre "highlightColorA" e "highlightColorB". Para um brilho/contorno mais
/// forte, activa Outline/Glow no material da fonte TMP — isso aplica-se ao
/// texto todo, mas combinado com a animação de cor por carácter já dá um
/// destaque bem visível.
/// </summary>
public class NpcDialogueBalloon : MonoBehaviour, INpcDialogueDisplay
{
    [Header("Referências")]
    [SerializeField] private GameObject panelRoot;
    [SerializeField] private TMP_Text nameLabel;
    [SerializeField] private TMP_Text bodyText;
    [SerializeField] private GameObject continueIndicator;

    [Header("Efeito [shake]")]
    [Tooltip("Amplitude do tremor, em unidades do mesh do TMP.")]
    [SerializeField] private float shakeAmount = 2f;

    [Header("Efeito [highlight]")]
    [SerializeField] private float highlightSpeed = 4f;
    [SerializeField] private Color highlightColorA = Color.white;
    [SerializeField] private Color highlightColorB = new Color(1f, 0.85f, 0.2f);

    [Header("Calda (Etapa 8)")]
    [Tooltip("RectTransform da calda do balão (ex: um triângulo), filha de panelRoot. É rodada (eixo Z) para apontar para o falante de cada linha (NPC, player, ou outro NPC — ver DialogueLine.speaker). Deixa vazio para não ter calda.")]
    [SerializeField] private RectTransform tailTransform;

    [Tooltip("Câmara usada para converter a posição do falante (mundo) em coordenadas de ecrã. Vazio = Camera.main.")]
    [SerializeField] private Camera worldCamera;

    [Tooltip("Ajuste de ângulo (graus) para compensar a orientação por defeito do sprite da calda. Ex: se o sprite aponta para a direita a 0°, deixa 0; se aponta para baixo, usa 90 (ou -90, dependendo do sentido positivo do eixo Y do sprite).")]
    [SerializeField] private float tailAngleOffset;

    private PlayerInputRouter _input;
    private bool _continuePressed;

    private Transform _tailTarget;
    private Coroutine _tailRoutine;

    private void Awake()
    {
        if (bodyText != null)
            bodyText.overflowMode = TextOverflowModes.Page;

        if (panelRoot != null)
            panelRoot.SetActive(false);

        if (continueIndicator != null)
            continueIndicator.SetActive(false);

        if (tailTransform != null)
            tailTransform.gameObject.SetActive(false);

        if (worldCamera == null)
            worldCamera = Camera.main;
    }

    private void OnDisable()
    {
        Unsubscribe();
    }

    public IEnumerator ShowLine(NpcController npc, string speakerName, string text, float charsPerSecond, Transform speakerTransform)
    {
        if (bodyText == null)
        {
            Debug.LogWarning($"[{name}] NpcDialogueBalloon: 'bodyText' não está atribuído.", this);
            yield break;
        }

        Subscribe(npc);

        if (panelRoot != null) panelRoot.SetActive(true);

        if (nameLabel != null)
        {
            bool hasName = !string.IsNullOrEmpty(speakerName);
            nameLabel.gameObject.SetActive(hasName);
            nameLabel.text = speakerName;
        }

        SetTailTarget(speakerTransform);

        var pages = DialogueMarkupParser.Parse(text);

        for (int p = 0; p < pages.Count; p++)
            yield return ShowPage(pages[p], charsPerSecond);

        Unsubscribe();
    }

    public void Hide(NpcController npc)
    {
        Unsubscribe();
        StopAllCoroutines();
        _tailRoutine = null;

        if (continueIndicator != null) continueIndicator.SetActive(false);
        if (tailTransform != null) tailTransform.gameObject.SetActive(false);
        if (panelRoot != null) panelRoot.SetActive(false);
    }

    // ---------------- Calda (Etapa 8) ----------------

    /// <summary>Define para onde a calda aponta nesta linha e (re)inicia a actualização contínua, se houver uma calda configurada.</summary>
    private void SetTailTarget(Transform target)
    {
        _tailTarget = target;

        if (tailTransform == null) return;

        if (_tailTarget == null)
        {
            tailTransform.gameObject.SetActive(false);
            return;
        }

        tailTransform.gameObject.SetActive(true);
        UpdateTail();

        if (_tailRoutine == null)
            _tailRoutine = StartCoroutine(UpdateTailRoutine());
    }

    private IEnumerator UpdateTailRoutine()
    {
        while (true)
        {
            UpdateTail();
            yield return null;
        }
    }

    /// <summary>Roda "tailTransform" (eixo Z) para apontar da sua posição no ecrã para a posição de "_tailTarget" no ecrã.</summary>
    private void UpdateTail()
    {
        if (tailTransform == null || _tailTarget == null) return;

        var cam = worldCamera != null ? worldCamera : Camera.main;
        if (cam == null) return;

        Vector2 targetScreenPos = cam.WorldToScreenPoint(_tailTarget.position);
        Vector2 tailScreenPos = RectTransformUtility.WorldToScreenPoint(null, tailTransform.position);

        Vector2 direction = targetScreenPos - tailScreenPos;
        if (direction.sqrMagnitude < 0.0001f) return;

        float angle = Mathf.Atan2(direction.y, direction.x) * Mathf.Rad2Deg;
        tailTransform.localRotation = Quaternion.Euler(0f, 0f, angle + tailAngleOffset);
    }

    // ---------------- Páginas ----------------

    private IEnumerator ShowPage(DialogueParsedPage page, float charsPerSecond)
    {
        bodyText.text = page.displayText;
        bodyText.maxVisibleCharacters = 0;
        bodyText.ForceMeshUpdate();

        if (continueIndicator != null) continueIndicator.SetActive(false);

        Coroutine effectsRoutine = null;
        if (page.effects.Count > 0)
            effectsRoutine = StartCoroutine(AnimateEffects(page));

        // ---- Efeito de escrita ----
        float delay = charsPerSecond > 0f ? 1f / charsPerSecond : 0f;

        _continuePressed = false;
        int waitCursor = 0;

        for (int charIndex = 0; charIndex <= page.visibleCharCount; charIndex++)
        {
            // Pausas [wait=x] que ocorrem antes deste carácter.
            while (waitCursor < page.waits.Count && page.waits[waitCursor].charIndex == charIndex)
            {
                float seconds = page.waits[waitCursor].seconds;
                waitCursor++;

                float waited = 0f;
                while (waited < seconds)
                {
                    if (_continuePressed) { _continuePressed = false; break; }
                    waited += Time.deltaTime;
                    yield return null;
                }
            }

            bodyText.maxVisibleCharacters = charIndex;

            if (charIndex >= page.visibleCharCount) break;

            if (_continuePressed)
            {
                _continuePressed = false;
                bodyText.maxVisibleCharacters = page.visibleCharCount;
                break;
            }

            if (delay > 0f)
            {
                float elapsed = 0f;
                while (elapsed < delay)
                {
                    if (_continuePressed) break;
                    elapsed += Time.deltaTime;
                    yield return null;
                }
            }
        }

        bodyText.maxVisibleCharacters = page.visibleCharCount;

        // ---- Espera o player continuar / fechar a página ----
        if (continueIndicator != null) continueIndicator.SetActive(true);

        _continuePressed = false;
        while (!_continuePressed)
            yield return null;
        _continuePressed = false;

        if (continueIndicator != null) continueIndicator.SetActive(false);

        if (effectsRoutine != null)
            StopCoroutine(effectsRoutine);
    }

    // ---------------- Efeitos visuais por carácter ----------------

    private IEnumerator AnimateEffects(DialogueParsedPage page)
    {
        while (true)
        {
            bodyText.ForceMeshUpdate();
            var textInfo = bodyText.textInfo;

            bool changed = false;

            foreach (var effect in page.effects)
            {
                int from = Mathf.Max(0, effect.startIndex);
                int to = Mathf.Min(effect.endIndex, textInfo.characterCount);
                to = Mathf.Min(to, bodyText.maxVisibleCharacters);

                for (int charIndex = from; charIndex < to; charIndex++)
                {
                    var charInfo = textInfo.characterInfo[charIndex];
                    if (!charInfo.isVisible) continue;

                    int matIndex = charInfo.materialReferenceIndex;
                    int vertIndex = charInfo.vertexIndex;

                    var verts = textInfo.meshInfo[matIndex].vertices;
                    var colors = textInfo.meshInfo[matIndex].colors32;

                    switch (effect.type)
                    {
                        case DialogueEffectType.Shake:
                            Vector3 offset = new Vector3(
                                (Mathf.PerlinNoise(Time.time * 28f, charIndex * 0.73f) - 0.5f) * shakeAmount,
                                (Mathf.PerlinNoise(charIndex * 0.73f, Time.time * 28f) - 0.5f) * shakeAmount,
                                0f);

                            for (int v = 0; v < 4; v++)
                                verts[vertIndex + v] += offset;
                            break;

                        case DialogueEffectType.Highlight:
                            float t = (Mathf.Sin(Time.time * highlightSpeed + charIndex * 0.35f) + 1f) * 0.5f;
                            Color32 highlightColor = Color32.Lerp(highlightColorA, highlightColorB, t);

                            for (int v = 0; v < 4; v++)
                                colors[vertIndex + v] = highlightColor;
                            break;
                    }

                    changed = true;
                }
            }

            if (changed)
            {
                for (int m = 0; m < textInfo.meshInfo.Length; m++)
                {
                    var meshInfo = textInfo.meshInfo[m];
                    meshInfo.mesh.vertices = meshInfo.vertices;
                    meshInfo.mesh.colors32 = meshInfo.colors32;
                    bodyText.UpdateGeometry(meshInfo.mesh, m);
                }
            }

            yield return null;
        }
    }

    // ---------------- Input ----------------

    private void Subscribe(NpcController npc)
    {
        Unsubscribe();

        if (npc == null || npc.Player == null) return;

        _input = npc.Player.GetComponent<PlayerInputRouter>();
        if (_input != null)
            _input.InteractPressed += OnInteractPressed;
    }

    private void Unsubscribe()
    {
        if (_input != null)
            _input.InteractPressed -= OnInteractPressed;

        _input = null;
    }

    private void OnInteractPressed()
    {
        _continuePressed = true;

        // Mitigação do conflito de InteractPressed (pedido "InteractionManager"):
        // o balão de diálogo está activo, por isso este toque pertence ao
        // diálogo — outros sistemas (NpcController, SafeHaven, AbilityRouter)
        // não devem reagir ao mesmo toque.
        if (_input != null) _input.InteractConsumed = true;
    }
}
